INSERT INTO cv_consulting_process_steps (number, title_es, title_en, description_es, description_en, sort_order) VALUES
  ('01', 'Diagnóstico Gratuito', 'Free Diagnosis', 'Analizamos tu negocio, identificamos cuellos de botella y oportunidades de automatización en una reunión de 30 minutos.', 'We analyze your business, identify bottlenecks and automation opportunities in a 30-minute meeting.', 0),
  ('02', 'Propuesta Personalizada', 'Custom Proposal', 'Diseñamos una solución a medida con ROI estimado, timeline realista y tecnologías específicas para tu caso.', 'We design a custom solution with estimated ROI, realistic timeline, and specific technologies for your case.', 1),
  ('03', 'Implementación Ágil', 'Agile Implementation', 'Ejecutamos en sprints cortos para que veas resultados rápidos. Entregamos MVPs funcionales en 2-4 semanas.', 'We execute in short sprints so you see quick results. We deliver functional MVPs in 2-4 weeks.', 2),
  ('04', 'Soporte Continuo', 'Continuous Support', 'Capacitamos a tu equipo y te acompañamos post-lanzamiento para garantizar el éxito a largo plazo.', 'We train your team and support you post-launch to ensure long-term success.', 3);
