  (9, 'de', 'nav.cta', 'Angebot Anfordern'),
  (10, 'de', 'hero.headline', 'Innovation und Komfort'),
  (11, 'de', 'hero.highlight', 'für Jedes Fahrzeug'),
  (12, 'de', 'hero.subheadline', 'Spezialisten für Verdunstungskühlung, Klimaanlage und Heizung für Wohnmobile, LKWs und Spezialfahrzeuge. Patentierte Technologie für maximalen Komfort.'),
  (13, 'de', 'hero.cta', 'Produkte Ansehen'),
  (14, 'de', 'hero.ctaSecondary', 'Kontaktieren'),
