  (19, 'de', 'about.sectionLabel', 'Unsere Geschichte'),
  (20, 'de', 'about.title', '30 Jahre führend in der Fahrzeugklimatisierung'),
  (21, 'de', 'about.description', 'Bei Neil Climatizadores widmen wir uns seit über 30 Jahren dem Design, der Herstellung und Installation von Verdunstungskühlern für Fahrzeuge. Wir zeichnen uns durch unser innovatives «Vorkühlungssystem» (Patent AR-031005B1) aus, eine einzigartige technologische Leistung auf den lateinamerikanischen und europäischen Märkten.'),
  (22, 'de', 'about.description2', 'Seit unseren Anfängen haben wir einen klaren Fokus beibehalten: Qualität, Entwicklung, Service und Engagement. Wir bleiben unserem Umweltengagement treu und entwickeln Produkte, die die Energieeffizienz optimieren.'),
  (23, 'de', 'about.pillars', '[{"title": "Qualität", "desc": "Beste Materialien und fortschrittliche Technologie für maximale Qualität in jedem Produkt."}, {"title": "Entwicklung", "desc": "Ständig auf der Suche nach neuen Technologien, um täglich die Qualität unserer Geräte zu verbessern."}, {"title": "Service", "desc": "Wir bieten unseren Kunden den besten Service mit klaren Antworten auf jede Anfrage."}, {"title": "Engagement", "desc": "Kontinuierliche Verbesserung und dauerhaftes Engagement gegenüber Kunden und Umwelt."}]'),
  (24, 'de', 'about.qualityPolicy', 'Qualitätspolitik'),
  (25, 'de', 'about.qualityDesc', 'Unsere Organisation ist der kontinuierlichen Verbesserung der Wirksamkeit unseres Systems verpflichtet, indem wir potenzielle Nichtkonformitäten antizipieren, um ein höheres Maß an Kundenzufriedenheit zu gewährleisten.'),
  (26, 'de', 'about.mediaTitle', 'Neil in den Medien'),
  (27, 'de', 'about.mediaSub', 'Anerkannt von Führungskräften der Transport- und Wohnmobilbranche'),
  (28, 'de', 'products.sectionLabel', 'Unsere Produkte'),
