  (60, 'de', 'preCooling.description2', 'Im Gegensatz zu herkömmlichen Kühlern aktiviert das Vorkühlungssystem eine Vorkühlung des Wassers vor der Verteilung, wodurch signifikant niedrigere Temperaturen bei gleichem Energieverbrauch erreicht werden.'),
  (61, 'de', 'preCooling.features', '[{"title": "Maximale Kühlung", "desc": "Temperatur bis zu 8°C niedriger als herkömmliche Systeme"}, {"title": "100% Lautlos", "desc": "Bürstenlose Pumpen der neuesten Generation, ohne Lärm oder Vibration"}, {"title": "Niedriger Verbrauch", "desc": "Überlegene Energieeffizienz, verlängert die Lebensdauer der Batterie"}, {"title": "Überlaufsicher", "desc": "Versiegeltes System, das Wasserüberläufe bei Kurven und Bremsungen verhindert"}]'),
  (62, 'de', 'preCooling.cta', 'Kühler Ansehen'),
  (63, 'de', 'europe.sectionLabel', 'Internationale Präsenz'),
  (64, 'de', 'europe.title', 'Neil in Europa'),
  (65, 'de', 'europe.description', 'Neil-Kühler werden im gesamten europäischen Kontinent für den anspruchsvollen Wohnmobil-Markt vertrieben. Ihre ausgezeichnete Leistung, ihr niedriger Batteriekonsum und ihre unvergleichliche Ästhetik machen sie zum idealen Begleiter für Wohnmobil-Abenteuer.'),
  (66, 'de', 'europe.description2', 'Wir verfügen über offizielle Händler in Frankreich, Italien, Spanien, Portugal, Deutschland und dem Vereinigten Königreich, die in jedem Land technischen Support und Garantie bieten.'),
  (67, 'de', 'europe.cta', 'Händler Finden'),
