  (133, 'en', 'about.sectionLabel', 'Our Story'),
  (134, 'en', 'about.title', '30 years leading vehicle climatization'),
  (135, 'en', 'about.description', 'At Neil Climatizadores, we have dedicated over 30 years to designing, manufacturing, and installing evaporative cooling systems for vehicles. We stand out for our innovative «Pre-Cooling System» (Patent AR-031005B1), a unique technological achievement in the Latin American and European markets.'),
  (136, 'en', 'about.description2', 'Since our beginnings, we have maintained a firm focus with clear goals: Quality, Development, Service, and Commitment. We remain firm in our commitment to the environment, developing products that optimize energy efficiency.'),
  (137, 'en', 'about.pillars', '[{"title": "Quality", "desc": "The best materials and advanced technology for maximum quality in every product."}, {"title": "Development", "desc": "Constantly searching for new technologies to daily improve the quality of our equipment."}, {"title": "Service", "desc": "We provide the best customer service with clear answers to every query."}, {"title": "Commitment", "desc": "Continuous improvement and permanent commitment to the customer and environment."}]'),
  (138, 'en', 'about.qualityPolicy', 'Quality Policy'),
  (139, 'en', 'about.qualityDesc', 'Our organization is committed to continuously improving the effectiveness of our system, anticipating potential non-conformities to ensure a higher level of customer satisfaction.'),
  (140, 'en', 'about.mediaTitle', 'Neil in the media'),
  (141, 'en', 'about.mediaSub', 'Recognized by leaders in the transport and motorhome industry'),
  (142, 'en', 'products.sectionLabel', 'Our Products'),
  (143, 'en', 'products.title', 'Solutions for every need'),
  (144, 'en', 'products.subtitle', 'Evaporative coolers, air conditioning, heaters, and energy solutions for motorhomes, trucks, and special vehicles.'),
  (145, 'en', 'products.categories.climatizadores.title', 'Evaporative Coolers'),
  (146, 'en', 'products.categories.climatizadores.subtitle', 'Exclusive Pre-Cooling System'),
  (147, 'en', 'products.categories.climatizadores.description', 'Evaporative coolers with the exclusive Pre-Cooling System (Patent AR-031005B1). Ultra-slim, 100% silent, and low power consumption.'),
  (148, 'en', 'products.categories.climatizadores.badge', 'Exclusive Patent'),
  (149, 'en', 'products.categories.aire-acondicionado.title', 'Air Conditioning'),
  (150, 'en', 'products.categories.aire-acondicionado.subtitle', 'Inverter Technology 12V/24V'),
  (151, 'en', 'products.categories.aire-acondicionado.description', 'Inverter air conditioners running on 12V and 24V for motorhomes and trucks. High efficiency with low battery consumption.'),
  (152, 'en', 'products.categories.aire-acondicionado.badge', 'Inverter'),
  (153, 'en', 'products.categories.calderas.title', 'Diesel Heaters'),
  (154, 'en', 'products.categories.calderas.subtitle', 'Efficient heating 12V/24V'),
  (155, 'en', 'products.categories.calderas.description', 'High-efficiency diesel heaters for vehicles. 100% silent operation without needing the engine on, and maximum winter comfort.'),
  (156, 'en', 'products.categories.calderas.badge', 'Diesel'),
  (157, 'en', 'products.categories.energia.title', 'Energy & Solar'),
  (158, 'en', 'products.categories.energia.subtitle', 'Portable generators'),
  (159, 'en', 'products.categories.energia.description', 'Genki and Bluetti lines of portable solar generators, solar kits, and charging stations. Autonomous energy for your adventures.'),
  (160, 'en', 'products.categories.energia.badge', 'Solar'),
  (161, 'en', 'products.categories.accesorios.title', 'Accessories'),
  (162, 'en', 'products.categories.accesorios.subtitle', 'More for your vehicle'),
  (163, 'en', 'products.categories.accesorios.description', 'Electric 12V Carjack and TPMS tire pressure monitoring system. Practical solutions for the demanding traveller.'),
  (164, 'en', 'products.categories.accesorios.badge', '12V'),
  (165, 'en', 'products.specsTitle', 'Specifications'),
  (166, 'en', 'products.viewMore', 'View more'),
