  (169, 'en', 'products.patentedBadge', 'Patented'),
  (170, 'en', 'preCooling.sectionLabel', 'Exclusive Technology'),
  (171, 'en', 'preCooling.title', 'Pre-Cooling System'),
  (172, 'en', 'preCooling.highlight', 'Patent AR-031005B1'),
  (173, 'en', 'preCooling.description', 'The exclusive Pre-Cooling System, patented by Neil (Patent: AR-031005B1), achieves maximum cooling power while maintaining a fresh and pleasant climate inside the vehicle.'),
  (174, 'en', 'preCooling.description2', 'Unlike conventional coolers, the Pre-Cooling system activates pre-cooling of the water before distribution, achieving significantly lower temperatures with the same energy consumption.'),
  (175, 'en', 'preCooling.features', '[{"title": "Maximum Cooling", "desc": "Temperature up to 8°C lower than conventional systems"}, {"title": "100% Silent", "desc": "State-of-the-art Brushless pumps, no noise or vibration"}, {"title": "Low Power Draw", "desc": "Superior energy efficiency, extends battery life"}, {"title": "Anti-Spill", "desc": "Sealed system that prevents water spills on curves and braking"}]'),
  (176, 'en', 'preCooling.cta', 'View Coolers'),
  (177, 'en', 'europe.sectionLabel', 'International Presence'),
  (178, 'en', 'europe.title', 'Neil in Europe'),
  (179, 'en', 'europe.description', 'Neil coolers are sold throughout Europe for the demanding motorhome market. Their excellent performance, low battery consumption, and unmatched aesthetics make them an ideal companion for motorhome adventures.'),
  (180, 'en', 'europe.description2', 'We have official dealers in France, Italy, Spain, Portugal, Germany, and the United Kingdom, providing technical support and warranty in each country.'),
