  (239, 'es', 'hero.highlight', 'para Cada Vehículo'),
  (240, 'es', 'hero.subheadline', 'Especialistas en climatización evaporativa, aires acondicionados y calderas para motorhomes, camiones y vehículos especiales. Tecnología patentada para el máximo confort.'),
  (241, 'es', 'hero.cta', 'Ver Productos'),
