  (247, 'es', 'about.sectionLabel', 'Nuestra Historia'),
  (248, 'es', 'about.title', '30 años liderando la climatización vehicular'),
  (249, 'es', 'about.description', 'En Neil Climatizadores nos dedicamos hace más de 30 años al diseño, fabricación e instalación de climatizadores evaporativos para vehículos. Nos destacamos por nuestro innovador «Sistema de Pre-Enfriado» (Patente AR-031005B1), logro tecnológico único en el mercado latinoamericano y europeo.'),
  (250, 'es', 'about.description2', 'Desde nuestros inicios hemos mantenido un enfoque firme con objetivos claros: Calidad, Desarrollo, Servicio y Compromiso. Nos mantenemos firmes en nuestro compromiso con el medio ambiente, elaborando productos que optimizan la eficiencia energética.'),
  (251, 'es', 'about.pillars', '[{"title": "Calidad", "desc": "Los mejores materiales y tecnología avanzada para la máxima calidad en cada producto."}, {"title": "Desarrollo", "desc": "Constantemente en búsqueda de nuevas tecnologías para mejorar día a día la calidad de nuestros equipos."}, {"title": "Servicio", "desc": "Brindamos la mejor atención a nuestros clientes con respuestas claras a cada consulta."}, {"title": "Compromiso", "desc": "Mejora continua y compromiso permanente con el cliente y el medio ambiente."}]'),
  (252, 'es', 'about.qualityPolicy', 'Política de Calidad'),
  (253, 'es', 'about.qualityDesc', 'Nuestra organización está comprometida con la mejora continua de la eficacia de nuestro sistema, anticipándonos a posibles no conformidades para garantizar un mayor nivel de satisfacción.'),
  (254, 'es', 'about.mediaTitle', 'Neil en los medios'),
  (255, 'es', 'about.mediaSub', 'Reconocidos por líderes de la industria del transporte y motorhome'),
  (256, 'es', 'products.sectionLabel', 'Nuestros Productos'),
  (257, 'es', 'products.title', 'Soluciones para cada necesidad'),
  (258, 'es', 'products.subtitle', 'Climatizadores, aires acondicionados, calderas y energía para motorhomes, camiones y vehículos especiales.'),
  (259, 'es', 'products.categories.climatizadores.title', 'Climatizadores Evaporativos'),
  (260, 'es', 'products.categories.climatizadores.subtitle', 'Únicos con Pre-Enfriado'),
  (261, 'es', 'products.categories.climatizadores.description', 'Climatizadores evaporativos con el exclusivo Sistema de Pre-Enfriado (Patente AR-031005B1). Ultra chatos, 100% silenciosos y de bajo consumo.'),
  (262, 'es', 'products.categories.climatizadores.badge', 'Patente Exclusiva'),
  (263, 'es', 'products.categories.aire-acondicionado.title', 'Aire Acondicionado'),
  (264, 'es', 'products.categories.aire-acondicionado.subtitle', 'Tecnología Inverter 12V/24V'),
  (265, 'es', 'products.categories.aire-acondicionado.description', 'Aires acondicionados con tecnología Inverter de 12V y 24V para motorhomes y camiones. Alta eficiencia y bajo consumo de batería.'),
  (266, 'es', 'products.categories.aire-acondicionado.badge', 'Inverter'),
  (267, 'es', 'products.categories.calderas.title', 'Calderas'),
  (268, 'es', 'products.categories.calderas.subtitle', 'Calefacción eficiente 12V/24V'),
  (269, 'es', 'products.categories.calderas.description', 'Calderas diesel de alta eficiencia para vehículos. Funcionamiento 100% silencioso, sin necesidad de motor encendido y máximo confort en invierno.'),
  (270, 'es', 'products.categories.calderas.badge', 'Diesel'),
  (271, 'es', 'products.categories.energia.title', 'Energía & Solar'),
  (272, 'es', 'products.categories.energia.subtitle', 'Generadores portátiles'),
  (273, 'es', 'products.categories.energia.description', 'Líneas Genki y Bluetti de generadores solares portátiles, kits solares y estaciones de carga. Energía autónoma para tus aventuras.'),
  (274, 'es', 'products.categories.energia.badge', 'Solar'),
  (275, 'es', 'products.categories.accesorios.title', 'Accesorios'),
  (276, 'es', 'products.categories.accesorios.subtitle', 'Más para tu vehículo'),
  (277, 'es', 'products.categories.accesorios.description', 'Carjack eléctrico 12V y sistema TPMS de monitoreo de presión de neumáticos. Soluciones prácticas para el viajero exigente.'),
  (278, 'es', 'products.categories.accesorios.badge', '12V'),
  (279, 'es', 'products.specsTitle', 'Especificaciones'),
  (280, 'es', 'products.viewMore', 'Ver más'),
