  (283, 'es', 'products.patentedBadge', 'Patentado'),
  (284, 'es', 'preCooling.sectionLabel', 'Tecnología Exclusiva'),
  (285, 'es', 'preCooling.title', 'Sistema de Pre-Enfriado'),
  (286, 'es', 'preCooling.highlight', 'Patente AR-031005B1'),
  (287, 'es', 'preCooling.description', 'El exclusivo Sistema de Pre-Enfriado, patentado por Neil (Patente: AR-031005B1), logra un máximo poder de enfriamiento manteniendo un clima fresco y agradable en el interior del vehículo.'),
  (288, 'es', 'preCooling.description2', 'A diferencia de los climatizadores convencionales, el sistema de Pre-Enfriado activa un enfriamiento previo del agua antes de su distribución, logrando temperaturas significativamente más bajas con el mismo consumo energético.'),
  (289, 'es', 'preCooling.features', '[{"title": "Máximo Enfriamiento", "desc": "Temperatura hasta 8°C más baja que los sistemas convencionales"}, {"title": "100% Silencioso", "desc": "Bombas Brushless de última generación, sin ruido ni vibración"}, {"title": "Bajo Consumo", "desc": "Eficiencia energética superior, prolonga la vida de la batería"}, {"title": "Anti-derrames", "desc": "Sistema sellado que evita derrames de agua en curvas y frenadas"}]'),
  (290, 'es', 'preCooling.cta', 'Ver Climatizadores'),
  (291, 'es', 'europe.sectionLabel', 'Presencia Internacional'),
  (292, 'es', 'europe.title', 'Neil en Europa'),
  (293, 'es', 'europe.description', 'Los climatizadores Neil son comercializados en todo el continente europeo para el exigente mercado del Motorhome. Su excelente rendimiento, bajo consumo de batería e inigualable estética lo hacen un complemento ideal para la aventura en autocaravana.'),
  (294, 'es', 'europe.description2', 'Contamos con representantes oficiales en Francia, Italia, España, Portugal, Alemania y Reino Unido, brindando soporte técnico y garantía en cada país.'),
