  (353, 'fr', 'hero.highlight', 'pour Chaque Véhicule'),
  (354, 'fr', 'hero.subheadline', 'Spécialistes en refroidissement évaporatif, climatisation et chauffage pour camping-cars, camions et véhicules spéciaux. Technologie brevetée pour un confort maximal.'),
  (355, 'fr', 'hero.cta', 'Voir les Produits'),
