  (361, 'fr', 'about.sectionLabel', 'Notre Histoire'),
  (362, 'fr', 'about.title', '30 ans à la tête de la climatisation véhicule'),
  (363, 'fr', 'about.description', 'Chez Neil Climatizadores, nous nous consacrons depuis plus de 30 ans à la conception, fabrication et installation de refroidisseurs évaporatifs pour véhicules. Nous nous distinguons par notre innovant «Système de Pré-Refroidissement» (Brevet AR-031005B1), une réalisation technologique unique sur les marchés latino-américain et européen.'),
  (364, 'fr', 'about.description2', 'Depuis nos débuts, nous avons maintenu un objectif clair: Qualité, Développement, Service et Engagement. Nous restons fermes dans notre engagement environnemental, en développant des produits qui optimisent l''efficacité énergétique.'),
  (365, 'fr', 'about.pillars', '[{"title": "Qualité", "desc": "Les meilleurs matériaux et une technologie avancée pour une qualité maximale dans chaque produit."}, {"title": "Développement", "desc": "Constamment à la recherche de nouvelles technologies pour améliorer chaque jour la qualité de nos équipements."}, {"title": "Service", "desc": "Nous offrons le meilleur service à nos clients avec des réponses claires à chaque demande."}, {"title": "Engagement", "desc": "Amélioration continue et engagement permanent envers le client et l''environnement."}]'),
  (366, 'fr', 'about.qualityPolicy', 'Politique Qualité'),
  (367, 'fr', 'about.qualityDesc', 'Notre organisation est engagée dans l''amélioration continue de l''efficacité de notre système, anticipant les non-conformités potentielles pour garantir un niveau de satisfaction client plus élevé.'),
  (368, 'fr', 'about.mediaTitle', 'Neil dans les médias'),
  (369, 'fr', 'about.mediaSub', 'Reconnu par les leaders du secteur des transports et du camping-car'),
  (370, 'fr', 'products.sectionLabel', 'Nos Produits'),
  (371, 'fr', 'products.title', 'Solutions pour chaque besoin'),
  (372, 'fr', 'products.subtitle', 'Refroidisseurs évaporatifs, climatisation, chauffage et énergie pour camping-cars, camions et véhicules spéciaux.'),
  (373, 'fr', 'products.categories.climatizadores.title', 'Refroidisseurs Évaporatifs'),
  (374, 'fr', 'products.categories.climatizadores.subtitle', 'Système de Pré-Refroidissement Exclusif'),
  (375, 'fr', 'products.categories.climatizadores.description', 'Refroidisseurs évaporatifs avec l''exclusif Système de Pré-Refroidissement (Brevet AR-031005B1). Ultra-plats, 100% silencieux et faible consommation.'),
  (376, 'fr', 'products.categories.climatizadores.badge', 'Brevet Exclusif'),
  (377, 'fr', 'products.categories.aire-acondicionado.title', 'Climatisation'),
  (378, 'fr', 'products.categories.aire-acondicionado.subtitle', 'Technologie Inverter 12V/24V'),
  (379, 'fr', 'products.categories.aire-acondicionado.description', 'Climatiseurs avec technologie Inverter 12V et 24V pour camping-cars et camions. Haute efficacité avec faible consommation de batterie.'),
  (380, 'fr', 'products.categories.aire-acondicionado.badge', 'Inverter'),
  (381, 'fr', 'products.categories.calderas.title', 'Chauffages Diesel'),
  (382, 'fr', 'products.categories.calderas.subtitle', 'Chauffage efficace 12V/24V'),
  (383, 'fr', 'products.categories.calderas.description', 'Chauffages diesel haute efficacité pour véhicules. Fonctionnement 100% silencieux sans moteur allumé et confort hivernal maximal.'),
  (384, 'fr', 'products.categories.calderas.badge', 'Diesel'),
  (385, 'fr', 'products.categories.energia.title', 'Énergie & Solaire'),
  (386, 'fr', 'products.categories.energia.subtitle', 'Générateurs portables'),
  (387, 'fr', 'products.categories.energia.description', 'Gammes Genki et Bluetti de générateurs solaires portables, kits solaires et stations de charge. Énergie autonome pour vos aventures.'),
  (388, 'fr', 'products.categories.energia.badge', 'Solaire'),
  (389, 'fr', 'products.categories.accesorios.title', 'Accessoires'),
  (390, 'fr', 'products.categories.accesorios.subtitle', 'Plus pour votre véhicule'),
  (391, 'fr', 'products.categories.accesorios.description', 'Cric électrique 12V et système TPMS de surveillance de la pression des pneus. Solutions pratiques pour le voyageur exigeant.'),
  (392, 'fr', 'products.categories.accesorios.badge', '12V'),
