  (398, 'fr', 'preCooling.sectionLabel', 'Technologie Exclusive'),
  (399, 'fr', 'preCooling.title', 'Système de Pré-Refroidissement'),
  (400, 'fr', 'preCooling.highlight', 'Brevet AR-031005B1'),
  (401, 'fr', 'preCooling.description', 'L''exclusif Système de Pré-Refroidissement, breveté par Neil (Brevet: AR-031005B1), atteint une puissance de refroidissement maximale tout en maintenant un climat frais et agréable à l''intérieur du véhicule.'),
  (402, 'fr', 'preCooling.description2', 'Contrairement aux refroidisseurs conventionnels, le système de Pré-Refroidissement active un pré-refroidissement de l''eau avant sa distribution, obtenant des températures significativement plus basses avec la même consommation d''énergie.'),
  (403, 'fr', 'preCooling.features', '[{"title": "Refroidissement Maximum", "desc": "Température jusqu''à 8°C inférieure aux systèmes conventionnels"}, {"title": "100% Silencieux", "desc": "Pompes Brushless de dernière génération, sans bruit ni vibration"}, {"title": "Faible Consommation", "desc": "Efficacité énergétique supérieure, prolonge la durée de vie de la batterie"}, {"title": "Anti-Débordement", "desc": "Système étanche qui évite les débordements d''eau dans les virages et au freinage"}]'),
  (404, 'fr', 'preCooling.cta', 'Voir les Refroidisseurs'),
  (405, 'fr', 'europe.sectionLabel', 'Présence Internationale'),
  (406, 'fr', 'europe.title', 'Neil en Europe'),
  (407, 'fr', 'europe.description', 'Les refroidisseurs Neil sont commercialisés dans toute l''Europe pour le marché exigeant des camping-cars. Leurs excellentes performances, leur faible consommation de batterie et leur esthétique incomparable en font un complément idéal pour l''aventure en camping-car.'),
  (408, 'fr', 'europe.description2', 'Nous disposons de revendeurs officiels en France, Italie, Espagne, Portugal, Allemagne et Royaume-Uni, offrant support technique et garantie dans chaque pays.'),
