  (467, 'it', 'hero.highlight', 'per Ogni Veicolo'),
  (468, 'it', 'hero.subheadline', 'Specialisti in raffrescamento evaporativo, aria condizionata e riscaldamento per camper, autocarri e veicoli speciali. Tecnologia brevettata per il massimo comfort.'),
  (469, 'it', 'hero.cta', 'Vedi Prodotti'),
  (470, 'it', 'hero.ctaSecondary', 'Contattaci'),
