  (474, 'it', 'hero.statLanguages', 'Lingue di supporto'),
  (475, 'it', 'about.sectionLabel', 'La Nostra Storia'),
  (476, 'it', 'about.title', '30 anni alla guida della climatizzazione veicolare'),
  (477, 'it', 'about.description', 'Da Neil Climatizadores ci dedichiamo da oltre 30 anni alla progettazione, produzione e installazione di raffrescatori evaporativi per veicoli. Ci distinguiamo per l''innovativo «Sistema di Pre-Raffreddamento» (Brevetto AR-031005B1), un risultato tecnologico unico nel mercato latinoamericano ed europeo.'),
  (478, 'it', 'about.description2', 'Sin dagli inizi abbiamo mantenuto un focus solido con obiettivi chiari: Qualità, Sviluppo, Servizio e Impegno. Rimaniamo fermi nel nostro impegno ambientale, sviluppando prodotti che ottimizzano l''efficienza energetica.'),
  (479, 'it', 'about.pillars', '[{"title": "Qualità", "desc": "I migliori materiali e tecnologia avanzata per la massima qualità in ogni prodotto."}, {"title": "Sviluppo", "desc": "Costantemente alla ricerca di nuove tecnologie per migliorare giorno dopo giorno la qualità dei nostri apparecchi."}, {"title": "Servizio", "desc": "Offriamo il miglior servizio ai nostri clienti con risposte chiare ad ogni richiesta."}, {"title": "Impegno", "desc": "Miglioramento continuo e impegno permanente verso il cliente e l''ambiente."}]'),
  (480, 'it', 'about.qualityPolicy', 'Politica della Qualità'),
  (481, 'it', 'about.qualityDesc', 'La nostra organizzazione è impegnata nel miglioramento continuo dell''efficacia del nostro sistema, anticipando possibili non conformità per garantire un maggiore livello di soddisfazione del cliente.'),
  (482, 'it', 'about.mediaTitle', 'Neil sui media'),
  (483, 'it', 'about.mediaSub', 'Riconosciuto dai leader del settore dei trasporti e del camper'),
  (484, 'it', 'products.sectionLabel', 'I Nostri Prodotti'),
  (485, 'it', 'products.title', 'Soluzioni per ogni esigenza'),
  (486, 'it', 'products.subtitle', 'Raffrescatori evaporativi, aria condizionata, caldaie e sistemi energetici per camper, autocarri e veicoli speciali.'),
  (487, 'it', 'products.categories.climatizadores.title', 'Raffrescatori Evaporativi'),
  (488, 'it', 'products.categories.climatizadores.subtitle', 'Esclusivo Sistema di Pre-Raffreddamento'),
  (489, 'it', 'products.categories.climatizadores.description', 'Raffrescatori evaporativi con il esclusivo Sistema di Pre-Raffreddamento (Brevetto AR-031005B1). Ultra-piatti, 100% silenziosi e a basso consumo.'),
  (490, 'it', 'products.categories.climatizadores.badge', 'Brevetto Esclusivo'),
  (491, 'it', 'products.categories.aire-acondicionado.title', 'Aria Condizionata'),
  (492, 'it', 'products.categories.aire-acondicionado.subtitle', 'Tecnologia Inverter 12V/24V'),
  (493, 'it', 'products.categories.aire-acondicionado.description', 'Aria condizionata con tecnologia Inverter a 12V e 24V per camper e autocarri. Alta efficienza con basso consumo della batteria.'),
  (494, 'it', 'products.categories.aire-acondicionado.badge', 'Inverter'),
  (495, 'it', 'products.categories.calderas.title', 'Riscaldatori Diesel'),
  (496, 'it', 'products.categories.calderas.subtitle', 'Riscaldamento efficiente 12V/24V'),
  (497, 'it', 'products.categories.calderas.description', 'Riscaldatori diesel ad alta efficienza per veicoli. Funzionamento 100% silenzioso senza bisogno di tenere il motore acceso e massimo comfort invernale.'),
  (498, 'it', 'products.categories.calderas.badge', 'Diesel'),
  (499, 'it', 'products.categories.energia.title', 'Energia & Solare'),
  (500, 'it', 'products.categories.energia.subtitle', 'Generatori portatili'),
  (501, 'it', 'products.categories.energia.description', 'Linee Genki e Bluetti di generatori solari portatili, kit solari e stazioni di ricarica. Energia autonoma per le tue avventure.'),
  (502, 'it', 'products.categories.energia.badge', 'Solare'),
  (503, 'it', 'products.categories.accesorios.title', 'Accessori'),
  (504, 'it', 'products.categories.accesorios.subtitle', 'Di più per il tuo veicolo'),
  (505, 'it', 'products.categories.accesorios.description', 'Carjack elettrico 12V e sistema TPMS di monitoraggio della pressione degli pneumatici. Soluzioni pratiche per il viaggiatore esigente.'),
  (506, 'it', 'products.categories.accesorios.badge', '12V'),
  (507, 'it', 'products.specsTitle', 'Specifiche'),
  (508, 'it', 'products.viewMore', 'Vedi di più'),
  (509, 'it', 'products.buyNow', 'Acquista'),
  (510, 'it', 'products.newBadge', 'Nuovo'),
  (511, 'it', 'products.patentedBadge', 'Brevettato'),
  (512, 'it', 'preCooling.sectionLabel', 'Tecnologia Esclusiva'),
  (513, 'it', 'preCooling.title', 'Sistema di Pre-Raffreddamento'),
  (514, 'it', 'preCooling.highlight', 'Brevetto AR-031005B1'),
  (515, 'it', 'preCooling.description', 'L''esclusivo Sistema di Pre-Raffreddamento, brevettato da Neil (Brevetto: AR-031005B1), raggiunge la massima potenza di raffrescamento mantenendo un clima fresco e piacevole all''interno del veicolo.'),
  (516, 'it', 'preCooling.description2', 'A differenza dei raffrescatori convenzionali, il sistema di Pre-Raffreddamento attiva un pre-raffreddamento dell''acqua prima della distribuzione, ottenendo temperature significativamente più basse con lo stesso consumo energetico.'),
  (517, 'it', 'preCooling.features', '[{"title": "Massimo Raffrescamento", "desc": "Temperatura fino a 8°C inferiore rispetto ai sistemi convenzionali"}, {"title": "100% Silenzioso", "desc": "Pompe Brushless di ultima generazione, senza rumore né vibrazione"}, {"title": "Basso Consumo", "desc": "Efficienza energetica superiore, prolunga la vita della batteria"}, {"title": "Anti-Versamento", "desc": "Sistema sigillato che evita versamenti d''acqua in curva e in frenata"}]'),
  (518, 'it', 'preCooling.cta', 'Vedi Raffrescatori'),
  (519, 'it', 'europe.sectionLabel', 'Presenza Internazionale'),
  (520, 'it', 'europe.title', 'Neil in Europa'),
  (521, 'it', 'europe.description', 'I raffrescatori Neil sono commercializzati in tutto il continente europeo per l''esigente mercato dei camper. Le loro eccellenti prestazioni, il basso consumo della batteria e l''estetica ineguagliabile li rendono un complemento ideale per l''avventura in autocaravan.'),
  (522, 'it', 'europe.description2', 'Disponiamo di rivenditori ufficiali in Francia, Italia, Spagna, Portogallo, Germania e Regno Unito, fornendo supporto tecnico e garanzia in ogni paese.'),
  (523, 'it', 'europe.cta', 'Trova un Rivenditore'),
