  (589, 'pt', 'about.sectionLabel', 'Nossa História'),
  (590, 'pt', 'about.title', '30 anos liderando a climatização veicular'),
  (591, 'pt', 'about.description', 'Na Neil Climatizadores, nos dedicamos há mais de 30 anos ao design, fabricação e instalação de climatizadores evaporativos para veículos. Destacamo-nos pelo nosso inovador «Sistema de Pré-Resfriamento» (Patente AR-031005B1), uma conquista tecnológica única nos mercados latino-americano e europeu.'),
  (592, 'pt', 'about.description2', 'Desde o início, mantivemos um foco firme com objetivos claros: Qualidade, Desenvolvimento, Serviço e Compromisso. Mantemo-nos firmes em nosso compromisso com o meio ambiente, desenvolvendo produtos que otimizam a eficiência energética.'),
  (593, 'pt', 'about.pillars', '[{"title": "Qualidade", "desc": "Os melhores materiais e tecnologia avançada para máxima qualidade em cada produto."}, {"title": "Desenvolvimento", "desc": "Constantemente em busca de novas tecnologias para melhorar cada dia a qualidade dos nossos equipamentos."}, {"title": "Serviço", "desc": "Oferecemos o melhor atendimento aos nossos clientes com respostas claras a cada consulta."}, {"title": "Compromisso", "desc": "Melhoria contínua e compromisso permanente com o cliente e o meio ambiente."}]'),
  (594, 'pt', 'about.qualityPolicy', 'Política de Qualidade'),
  (595, 'pt', 'about.qualityDesc', 'Nossa organização está comprometida com a melhoria contínua da eficácia do nosso sistema, antecipando possíveis não conformidades para garantir um maior nível de satisfação do cliente.'),
  (596, 'pt', 'about.mediaTitle', 'Neil na mídia'),
  (597, 'pt', 'about.mediaSub', 'Reconhecido pelos líderes do setor de transporte e motorhome'),
  (598, 'pt', 'products.sectionLabel', 'Nossos Produtos'),
  (599, 'pt', 'products.title', 'Soluções para cada necessidade'),
  (600, 'pt', 'products.subtitle', 'Climatizadores evaporativos, ar-condicionado, caldeiras e energia para motorhomes, caminhões e veículos especiais.'),
  (601, 'pt', 'products.categories.climatizadores.title', 'Climatizadores Evaporativos'),
  (602, 'pt', 'products.categories.climatizadores.subtitle', 'Sistema de Pré-Resfriamento Exclusivo'),
  (603, 'pt', 'products.categories.climatizadores.description', 'Climatizadores evaporativos com o exclusivo Sistema de Pré-Resfriamento (Patente AR-031005B1). Ultra-planos, 100% silenciosos e baixo consumo.'),
  (604, 'pt', 'products.categories.climatizadores.badge', 'Patente Exclusiva'),
  (605, 'pt', 'products.categories.aire-acondicionado.title', 'Ar-Condicionado'),
  (606, 'pt', 'products.categories.aire-acondicionado.subtitle', 'Tecnologia Inverter 12V/24V'),
  (607, 'pt', 'products.categories.aire-acondicionado.description', 'Ar-condicionados com tecnologia Inverter 12V e 24V para motorhomes e caminhões. Alta eficiência com baixo consumo de bateria.'),
  (608, 'pt', 'products.categories.aire-acondicionado.badge', 'Inverter'),
  (609, 'pt', 'products.categories.calderas.title', 'Aquecedores Diesel'),
  (610, 'pt', 'products.categories.calderas.subtitle', 'Aquecimento eficiente 12V/24V'),
  (611, 'pt', 'products.categories.calderas.description', 'Aquecedores diesel de alta eficiência para veículos. Funcionamento 100% silencioso sem necessidade de manter o motor ligado e máximo conforto no inverno.'),
  (612, 'pt', 'products.categories.calderas.badge', 'Diesel'),
  (613, 'pt', 'products.categories.energia.title', 'Energia & Solar'),
  (614, 'pt', 'products.categories.energia.subtitle', 'Geradores portáteis'),
  (615, 'pt', 'products.categories.energia.description', 'Linhas Genki e Bluetti de geradores solares portáteis, kits solares e estações de carregamento. Energia autônoma para suas aventuras.'),
  (616, 'pt', 'products.categories.energia.badge', 'Solar'),
  (617, 'pt', 'products.categories.accesorios.title', 'Acessórios'),
  (618, 'pt', 'products.categories.accesorios.subtitle', 'Mais para o seu veículo'),
  (619, 'pt', 'products.categories.accesorios.description', 'Macaco elétrico 12V e sistema TPMS de monitoramento de pressão dos pneus. Soluções práticas para o viajante exigente.'),
  (620, 'pt', 'products.categories.accesorios.badge', '12V'),
  (621, 'pt', 'products.specsTitle', 'Especificações'),
