  (626, 'pt', 'preCooling.sectionLabel', 'Tecnologia Exclusiva'),
  (627, 'pt', 'preCooling.title', 'Sistema de Pré-Resfriamento'),
  (628, 'pt', 'preCooling.highlight', 'Patente AR-031005B1'),
  (629, 'pt', 'preCooling.description', 'O exclusivo Sistema de Pré-Resfriamento, patenteado pela Neil (Patente: AR-031005B1), alcança máximo poder de resfriamento mantendo um clima fresco e agradável no interior do veículo.'),
  (630, 'pt', 'preCooling.description2', 'Ao contrário dos climatizadores convencionais, o sistema de Pré-Resfriamento ativa um pré-resfriamento da água antes de sua distribuição, obtendo temperaturas significativamente mais baixas com o mesmo consumo energético.'),
  (631, 'pt', 'preCooling.features', '[{"title": "Máximo Resfriamento", "desc": "Temperatura até 8°C mais baixa do que os sistemas convencionais"}, {"title": "100% Silencioso", "desc": "Bombas Brushless de última geração, sem ruído ou vibração"}, {"title": "Baixo Consumo", "desc": "Eficiência energética superior, prolonga a vida da bateria"}, {"title": "Anti-Derramamento", "desc": "Sistema vedado que evita derramamentos de água em curvas e frenagens"}]'),
  (632, 'pt', 'preCooling.cta', 'Ver Climatizadores'),
  (633, 'pt', 'europe.sectionLabel', 'Presença Internacional'),
  (634, 'pt', 'europe.title', 'Neil na Europa'),
  (635, 'pt', 'europe.description', 'Os climatizadores Neil são comercializados em todo o continente europeu para o exigente mercado de motorhomes. Seu excelente desempenho, baixo consumo de bateria e estética incomparável os tornam um complemento ideal para aventuras em autocaravana.'),
  (636, 'pt', 'europe.description2', 'Contamos com revendedores oficiais na França, Itália, Espanha, Portugal, Alemanha e Reino Unido, fornecendo suporte técnico e garantia em cada país.'),
